#include <openssl/evp.h>
#include <openssl/rsa.h>
#include <openssl/err.h>
#include <stdio.h>
#include <string.h>

// Function to generate an RSA key pair
int generate_rsa_key_pair(RSA **rsa_key, int bits) {
    EVP_PKEY_CTX *pkey_ctx = NULL;
    size_t outlen = 0;
    int ret = 0;

    // 1. Create the context
    if (!(pkey_ctx = EVP_PKEY_CTX_new_id(EVP_PKEY_RSA, NULL))) {
        fprintf(stderr, "Error creating RSA context\n");
        return -1;
    }

    // 2. Initialize the RSA key generation parameters
    if (EVP_PKEY_keygen_init(pkey_ctx) <= 0) {
        fprintf(stderr, "Error initializing RSA key generation\n");
        EVP_PKEY_CTX_free(pkey_ctx);
        return -1;
    }

    // 3. Set the desired key size (2048 bits)
    if (EVP_PKEY_CTX_set_rsa_keygen_bits(pkey_ctx, bits) <= 0) {
        fprintf(stderr, "Error setting RSA key size\n");
        EVP_PKEY_CTX_free(pkey_ctx);
        return -1;
    }

    // 4. Generate the key
    if (!rsa_key || !EVP_PKEY_keygen(pkey_ctx, rsa_key)) {
        fprintf(stderr, "Error generating RSA key\n");
        EVP_PKEY_CTX_free(pkey_ctx);
        return -1;
    }

    // Cleanup
    EVP_PKEY_CTX_free(pkey_ctx);

    return 0;
}

int main() {
    RSA *rsa_key = NULL;
    int result;
    int key_bits = 2048;

    printf("Attempting to generate a %d-bit RSA key pair...\n", key_bits);

    result = generate_rsa_key_pair(&rsa_key, key_bits);

    if (result == 0) {
        printf("Successfully generated RSA key pair.\n");

        // In a real application, you would now use rsa_key
        // For demonstration, we just confirm success.

    } else {
        fprintf(stderr, "Key generation failed.\n");
    }

    if (rsa_key) {
        RSA_free(rsa_key);
    }

    return 0;
}
